1	import type {
2	  MarketListFilters,
3	  MarketListSort,
4	  MarketListStatusFilter,
5	  MarketStatus,
6	} from "@/lib/api/types";
7	
8	export interface NormalizedMarketListFilters {
9	  status?: MarketStatus;
10	  sort?: MarketListSort;
11	  q?: string;
12	}
13	
14	export interface MarketListQueryKeyFilters {
15	  status: MarketStatus | null;
16	  sort: MarketListSort | null;
17	  q: string | null;
18	}
19	
20	const MARKET_STATUSES: MarketStatus[] = ["active", "resolved", "closed", "draft"];
21	const MARKET_SORTS: MarketListSort[] = ["volume", "liquidity", "created"];
22	
23	export function isMarketListStatusFilter(value: string | null): value is MarketListStatusFilter {
24	  return value === "all" || MARKET_STATUSES.includes(value as MarketStatus);
25	}
26	
27	export function isMarketListSort(value: string | null): value is MarketListSort {
28	  return MARKET_SORTS.includes(value as MarketListSort);
29	}
30	
31	export function normalizeMarketListFilters(
32	  filters: MarketListFilters = {},
33	): NormalizedMarketListFilters {
34	  const normalized: NormalizedMarketListFilters = {};
35	
36	  if (filters.status && filters.status !== "all") {
37	    normalized.status = filters.status;
38	  }
39	
40	  if (filters.sort) {
41	    normalized.sort = filters.sort;
42	  }
43	
44	  const q = filters.q?.trim();
45	  if (q) {
46	    normalized.q = q;
47	  }
48	
49	  return normalized;
50	}
51	
52	export function marketListQueryKey(
53	  filters: MarketListFilters = {},
54	): MarketListQueryKeyFilters {
55	  const normalized = normalizeMarketListFilters(filters);
56	
57	  return {
58	    status: normalized.status ?? null,
59	    sort: normalized.sort ?? null,
60	    q: normalized.q ?? null,
61	  };
62	}
63	
64	export function marketListSearchParams(
65	  filters: MarketListFilters = {},
66	): URLSearchParams {
67	  const normalized = normalizeMarketListFilters(filters);
68	  const params = new URLSearchParams();
69	
70	  if (normalized.status) {
71	    params.set("status", normalized.status);
72	  }
73	
74	  if (normalized.sort) {
75	    params.set("sort", normalized.sort);
76	  }
77	
78	  if (normalized.q) {
79	    params.set("q", normalized.q);
80	  }
81	
82	  return params;
83	}
84	
85	export function readMarketListFiltersFromSearchParams(
86	  searchParams: URLSearchParams,
87	): NormalizedMarketListFilters {
88	  const status = searchParams.get("status");
89	  const sort = searchParams.get("sort");
90	
91	  return normalizeMarketListFilters({
92	    status: isMarketListStatusFilter(status) ? status : undefined,
93	    sort: isMarketListSort(sort) ? sort : undefined,
94	    q: searchParams.get("q") ?? undefined,
95	  });
96	}
